import { Link } from "react-router-dom"

const DUMMY_EVENTS = [
    {
        id: "e1",
        title: "Some event"
    },
    {
        id: "e2",
        title: "Another event"
    }
]

export default function Events() {
    return <>
        <h1>this is events page.</h1>
        <ul>
            {DUMMY_EVENTS.map(event => <Link></Link>)}
        </ul>
    </>
};
